// Get the full text from previous node
const content = $json["data"];  // your node output field

// Use regex to get client name
const match = content.match(/Client:\s*(.*)/);

// Return JSON with clientName and full proposal
return [
  {
    json: {
      clientName: match ? match[1] : "Unknown Client",
      currentProposal: content
    }
  }
];

